"use strict";parserFactory.register("sto.cx",()=>new StocxParser);class StocxParser extends Parser{constructor(){super()}getChapterUrls(e){let t=StocxParser.findScriptElementWithChapterInfo(e),r=[];if(0<t.length){let e=StocxParser.extractChapterGenInfo(t[0]);for(let t=1;t<=e.maxPage;++t)r.push({sourceUrl:`https://www.sto.cx/book-${e.bookId}-${t}.html`,title:`${t}`})}return Promise.resolve(r)}static findScriptElementWithChapterInfo(e){return[...e.querySelectorAll("script")].filter(e=>e.textContent.includes(StocxParser.chapterGenTag)).map(e=>e.textContent)}static extractChapterGenInfo(e){let t=e.indexOf(StocxParser.chapterGenTag),r=e.substring(t).split(",");return{bookId:parseInt(r[1]),maxPage:parseInt(r[2])}}findContent(e){return e.querySelector("div#BookContent")}extractLanguage(){return"cn"}customRawDomToContentStep(e,t){let r=StocxParser.getTextNodesToFixUp(t);for(let e of r)e.nodeValue=StocxParser.fixMangledText(e.nodeValue)}static getTextNodesToFixUp(e){let t=null,r=[],o=document.createTreeWalker(e,NodeFilter.SHOW_TEXT,null,!1);for(;null!==(t=o.nextNode());)t.nodeValue.includes("%")&&r.push(t);return r}static fixMangledText(e){let t=[],r=0;for(;r<e.length;)if(StocxParser.isEncodeddByte(e,r))t.push(StocxParser.decodeByte(e,r)),r+=3;else{let o=StocxParser.getUtf8encoder().encode(e[r]);for(let e of o)t.push(e);++r}return StocxParser.getUtf8decoder().decode(new Uint8Array(t))}static isEncodeddByte(e,t){return t+2<e.length&&"%"===e[t]&&StocxParser.isHexChar(e[t+1])&&StocxParser.isHexChar(e[t+2])}static isHexChar(e){return!isNaN(parseInt(e[0],16))}static decodeByte(e,t){return parseInt(e.substring(t+1,t+3),16)}static getUtf8decoder(){return void 0===StocxParser.utf8decoder&&(StocxParser.utf8decoder=new TextDecoder("utf-8")),StocxParser.utf8decoder}static getUtf8encoder(){return void 0===StocxParser.utf8encoder&&(StocxParser.utf8encoder=new TextEncoder),StocxParser.utf8encoder}findChapterTitle(e){return e.querySelector("h1")}}StocxParser.chapterGenTag="ANP_goToPage(";